# Implementation Patterns — Copy These, Don't Reinvent

> Every new command follows ONE pattern. This bead is the single demonstration.
> Per LLM Gestalt Theory: one example replaces 5+ constraints.

## Pattern A: CLI Command (copy from exemplar.go:52-114)

```go
var myCmd = &cobra.Command{
    Use:   "mycommand [target] [db-path]",
    Short: "One-line description",
    Args:  cobra.RangeArgs(1, 2),  // or cobra.MaximumNArgs(1) for db-only
    RunE:  runMyCommand,
}

func init() {
    myCmd.Flags().BoolVar(&myJSON, "json", false, "Output as JSON")
}

func runMyCommand(cmd *cobra.Command, args []string) error {
    // 1. Parse args
    target := args[0]
    var dbPath string
    if len(args) >= 2 { dbPath = args[1] }
    if dbPath == "" {
        var err error
        dbPath, err = findDB()
        if err != nil { return err }
    }

    // 2. Open DB + get specID
    db, err := storage.Open(dbPath)
    if err != nil { return fmt.Errorf("open database: %w", err) }
    defer db.Close()
    specID, err := storage.GetFirstSpecID(db)
    if err != nil { return fmt.Errorf("no spec found: %w", err) }

    // 3. Call analysis
    result, err := mypackage.Analyze(db, specID, opts)
    if err != nil { return err }

    // 4. Render + print
    out, err := mypackage.Render(result, myJSON)
    if err != nil { return err }
    fmt.Print(out)
    return nil
}
```

## Pattern B: Render Function (copy from exemplar/render.go)

```go
func Render(result *MyResult, asJSON bool) (string, error) {
    if asJSON {
        data, err := json.MarshalIndent(result, "", "  ")
        if err != nil { return "", fmt.Errorf("marshal: %w", err) }
        return string(data) + "\n", nil
    }
    var b strings.Builder
    // ... build human output with fmt.Fprintf(&b, ...) ...
    return b.String(), nil
}
```

## Pattern C: Test Setup (copy from tests/exemplar_test.go:16-81)

```go
var sharedDB *testDB

type testDB struct {
    db     *sql.DB
    specID int64
}

func getTestDB(t *testing.T) (*sql.DB, int64) {
    t.Helper()
    if sharedDB != nil { return sharedDB.db, sharedDB.specID }
    manifestPath := filepath.Join(projectRoot(), "ddis-cli-spec", "manifest.yaml")
    dbPath := filepath.Join(t.TempDir(), "test.ddis.db")
    db, _ := storage.Open(dbPath)
    specID, _ := parser.ParseModularSpec(manifestPath, db)
    sharedDB = &testDB{db: db, specID: specID}
    return db, specID
}
```

## Pattern D: Query Function (copy from storage/queries.go)

```go
func ListThingsByFilter(db *sql.DB, specID int64, filter string) ([]Thing, error) {
    rows, err := db.Query(
        "SELECT col1, col2 FROM table WHERE spec_id = ? AND filter_col = ? ORDER BY col1",
        specID, filter)
    if err != nil { return nil, err }
    defer rows.Close()
    var results []Thing
    for rows.Next() {
        var t Thing
        if err := rows.Scan(&t.Col1, &t.Col2); err != nil { return nil, err }
        results = append(results, t)
    }
    return results, rows.Err()
}
```

