// modeBoost reorders same-priority recommendations based on cognitive mode.
// This is observation-driven attenuation, NOT prescription (APP-INV-026).
func modeBoost(mode string) map[string]int {
    switch mode {
    case "crystallization":
        return map[string]int{"witness": 2, "challenge": 2, "validate": 1}
    case "divergent":
        return map[string]int{"discover": 2, "explore": 2, "question": 1}
    case "convergent":
        return map[string]int{"validate": 2, "challenge": 1, "close": 1}
    case "incubation":
        return map[string]int{"context": 2, "review": 2, "summary": 1}
    default:
        return nil // no boost, use default order
