```go
// isConverged checks whether the spec has reached full convergence.
// Returns (converged bool, unmetCriteria []string).
// This is a PURE QUERY — no side effects, no event emission.
func isConverged(db *sql.DB, specID int64, currentDrift int) (bool, []string) {
    var unmet []string

    // Criterion 1: drift == 0
    if currentDrift > 0 {
        unmet = append(unmet, fmt.Sprintf("drift=%d (must be 0)", currentDrift))
    }

    // Criterion 2: all validation checks pass
    report, err := validator.Validate(db, specID, validator.ValidateOptions{})
    if err != nil {
        unmet = append(unmet, fmt.Sprintf("validation error: %v", err))
    } else if report.Failed > 0 {
        unmet = append(unmet, fmt.Sprintf("validation: %d/%d pass (%d failing)",
            report.Passed, report.TotalChecks, report.Failed))
    }

    // Criterion 3: all witnesses valid (none stale)
    staleCount, _ := witness.Refresh(db, specID)
    if staleCount > 0 {
        unmet = append(unmet, fmt.Sprintf("%d stale witness(es)", staleCount))
    }

    // Criterion 4: confidence plateau (delta==0 for 2+ iterations)
    // Read last 2 confidence snapshots from state
    iter := getCurrentIteration(db, specID) // helper to read refine_iteration from state
    if iter >= 2 {
        prev := getConfidenceArray(db, specID, iter-1)
        curr := getConfidenceArray(db, specID, iter)
        if prev != nil && curr != nil {
            allHigh := true
            plateau := true
            for i := 0; i < 5; i++ {
                if curr[i] < 8 {
                    allHigh = false
                    unmet = append(unmet, fmt.Sprintf("confidence[%d]=%d (must be >=8)", i, curr[i]))
                }
                if curr[i] != prev[i] {
                    plateau = false
                }
            }
            if !plateau {
                unmet = append(unmet, "confidence not plateaued (still changing)")
            }
            _ = allHigh // used above
        }
    }

    return len(unmet) == 0, unmet
}
```

